      "module_id": 1,
      "json_structure": "{\"headerImage\":\"\",\"questions\":[{\"id\":\"q_1776159093001\",\"type\":\"identification\",\"title\":\"Identify the following items\",\"subtitle\":\"\",\"showExplanations\":true,\"structures\":[\"http://localhost:3001/uploads/1776159121567-O,O-Acetals.png\",\"http://localhost:3001/uploads/1776159126016-S,S-Acetals.png\"],\"options\":[{\"text\":\"O,O-Acetals\",\"imageUrl\":\"\"},{\"text\":\"S,S-Acetals \",\"imageUrl\":\"\"}],\"correctAnswers\":{\"0\":\"O,O-Acetals\",\"1\":\"S,S-Acetals \"},\"hasCorrection\":true},{\"id\":\"q_1776159293488\",\"type\":\"abbreviation_flow\",\"title\":\"Choose one protecting group that can be removed by acid hydrolysis.\",\"subtitle\":\"Indicate: the structure of the protecting group and its abbreviation, type of protection, conditions of protection and removal.\",\"showExplanations\":false,\"explanationCorrect\":\"\",\"explanationCorrectImage\":\"\",\"explanationImprovable\":\"\",\"explanationImprovableImage\":\"\",\"abbreviationOptions\":[\"O,O-Acetals\",\"S,S-Acetals\"],\"protectionTypeOptions\":[\"Acetals\",\"Amides \",\"Carbonates\",\"Esters\",\"Ethers\",\"Imides\",\"N-Alkyl derivatives \"],\"correctAbbreviation\":\"O,O-Acetals\",\"baseImage\":\"http://localhost:3001/uploads/1776160042584-Carboxyl.png\",\"imageMapping\":{\"O,O-Acetals\":\"http://localhost:3001/uploads/1776160046125-O,O-Acetals.png\",\"S,S-Acetals\":\"http://localhost:3001/uploads/1776160050124-S,S-Acetals.png\"},\"arrow1Options\":[\"Propane-1,3-diol, TsOH\",\"Propane-1,3-dithiol, TsOH\"],\"arrow1Correct\":\"Propane-1,3-diol, TsOH\",\"arrow1Improvable\":[],\"arrow2Options\":[\"TsOH, H₂O, acetone or aq. HCl, TFA\",\"Hg(ClO₄)₂\"],\"arrow2Correct\":\"TsOH, H₂O, acetone or aq. HCl, TFA\",\"arrow2Improvable\":[],\"correctAbbreviations\":[\"O,O-Acetals\"],\"flowMapping\":{\"O,O-Acetals\":{\"arrow1\":\"Propane-1,3-diol, TsOH\",\"arrow2\":\"TsOH, H₂O, acetone or aq. HCl, TFA\",\"protectionType\":\"Acetals\"}}},{\"id\":\"q_1776159806991_235\",\"type\":\"abbreviation_flow\",\"title\":\"Choose one protecting group that can be removed by oxidation with a heavy metal.\",\"subtitle\":\"Indicate: the structure of the protecting group and its abbreviation, type of protection, conditions of protection and removal.\",\"showExplanations\":false,\"explanationCorrect\":\"\",\"explanationCorrectImage\":\"\",\"explanationImprovable\":\"\",\"explanationImprovableImage\":\"\",\"abbreviationOptions\":[\"O,O-Acetals\",\"S,S-Acetals\"],\"protectionTypeOptions\":[\"Acetals\",\"Amides \",\"Carbonates\",\"Esters\",\"Ethers\",\"Imides\",\"N-Alkyl derivatives \"],\"correctAbbreviation\":\"S,S-Acetals\",\"baseImage\":\"http://localhost:3001/uploads/1776160057060-Carboxyl.png\",\"imageMapping\":{\"O,O-Acetals\":\"http://localhost:3001/uploads/1776160060247-O,O-Acetals.png\",\"S,S-Acetals\":\"http://localhost:3001/uploads/1776160064451-S,S-Acetals.png\"},\"arrow1Options\":[\"Propane-1,3-diol, TsOH\",\"Propane-1,3-dithiol, TsOH\"],\"arrow1Correct\":\"Propane-1,3-diol, TsOH\",\"arrow1Improvable\":[],\"arrow2Options\":[\"TsOH, H₂O, acetone or aq. HCl, TFA\",\"Hg(ClO₄)₂\"],\"arrow2Correct\":\"TsOH, H₂O, acetone or aq. HCl, TFA\",\"arrow2Improvable\":[],\"correctAbbreviations\":[\"S,S-Acetals\"],\"flowMapping\":{\"S,S-Acetals\":{\"arrow1\":\"Propane-1,3-dithiol, TsOH\",\"arrow2\":\"Hg(ClO₄)₂\",\"protectionType\":\"Acetals\"}}}]}"
