    "2": {
      "id": 19,
      "module_id": 2,
      "json_structure": "{\"headerImage\":\"\",\"questions\":[{\"id\":\"q_1775030818535\",\"type\":\"true_false\",\"title\":\"Protecting groups are used to temporarily mask reactive functional groups during a multistep synthesis.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Protecting groups prevent a functional group from reacting while other transformations are carried out elsewhere in the molecule.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030851170\",\"type\":\"true_false\",\"title\":\"A good protecting group should be easy to introduce and remove under mild conditions.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Efficient protecting groups can be introduced using simple reaction steps and can be removed without affecting the rest of the molecule.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030885146_586\",\"type\":\"true_false\",\"title\":\"The use of protecting groups increases the number of steps in a synthetic route.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Protection and deprotection steps add extra reactions, which can increase time, cost, and reduce overall yield.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030900945_696\",\"type\":\"true_false\",\"title\":\"Protecting groups are unnecessary if a reaction is perfectly chemoselective.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"If the reaction selectively affects only the desired functional group, there is no need to mask others.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030926272_645\",\"type\":\"true_false\",\"title\":\"A protecting group should ideally be inert to the reagents used in subsequent reaction steps.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"The protecting group must remain stable throughout the synthesis.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030946307_831\",\"type\":\"true_false\",\"title\":\"Two protecting groups are orthogonal if one can be selectively removed without affecting the other and in any order. \",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Orthogonal strategies use protecting groups that respond to different conditions, enabling selective deprotection.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775030962644_207\",\"type\":\"true_false\",\"title\":\"Protecting groups are rarely used in the synthesis of complex molecules.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Protecting groups are frequently used in the synthesis of complex molecules.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true},{\"id\":\"q_1775030974720_288\",\"type\":\"true_false\",\"title\":\"The use of protecting groups is always avoided in modern synthetic design because they reduce atom economy.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Although chemists try to minimize protecting group steps to improve efficiency and sustainability, they are still frequently necessary in complex syntheses.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true},{\"id\":\"q_1775030993448_300\",\"type\":\"true_false\",\"title\":\"The incorporation of a protecting group may change steric hindrance around a reactive center.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Protecting groups can introduce steric bulk, which can affect reaction rates, selectivity, or accessibility of nearby functional groups.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775031009314_905\",\"type\":\"true_false\",\"title\":\"A protecting group must always be introduced before any other reaction step in a synthesis.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Protection is introduced only when needed, and the timing depends on the sequence of reactions.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true},{\"id\":\"q_1775031023137_401\",\"type\":\"true_false\",\"title\":\"Protecting groups can influence both chemoselectivity and regioselectivity of reactions.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"By blocking or modifying functional groups, protecting groups can redirect reactivity toward specific sites.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"true\",\"hasCorrection\":true},{\"id\":\"q_1775031040376_313\",\"type\":\"true_false\",\"title\":\"A protecting group strategy that requires harsh conditions for removal is always unsuitable.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"Harsh conditions may still be acceptable if the rest of the molecule is stable under those conditions.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true},{\"id\":\"q_1775031054741_906\",\"type\":\"true_false\",\"title\":\"The use of protecting groups generally improves the overall yield of a synthesis by preventing side reactions.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"While protecting groups can prevent undesired reactions, the additional steps usually lower overall yield, since each step has its own inefficiencies.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true},{\"id\":\"q_1775031068527_114\",\"type\":\"true_false\",\"title\":\"Protecting groups are unnecessary when two functional groups have identical reactivity.\",\"subtitle\":\"\",\"imageUrl\":\"\",\"showExplanations\":true,\"explanationCorrect\":\"If two groups have similar reactivity, it may actually be more necessary to protect one to achieve selective reaction.\",\"explanationCorrectImage\":\"\",\"correctAnswer\":\"false\",\"hasCorrection\":true}]}"
    },
